import os from "node:os";
import { describe, expect, it } from "vitest";
import { buildBitfabClientHeaders, buildBitfabRequestHeaders, } from "./clientHeaders.js";
const testPlatform = {
    authPath: "test",
    loginHint: "/test:login",
    setupHint: "/test:setup",
    updateHint: "/test:update",
    repo: "Test/test-plugin",
    cliBinary: "test-cli",
    displayName: "Test Client",
    supportsAutoUpdate: false,
    marketplaceName: "test",
    pluginName: "test",
    marketplacePreRegistered: false,
};
describe("buildBitfabClientHeaders", () => {
    it("includes the full bitfab-client identity header set", () => {
        const headers = buildBitfabClientHeaders("1.2.3", testPlatform);
        expect(headers["x-bitfab-client-name"]).toBe("test-cli");
        expect(headers["x-bitfab-client-display-name"]).toBe("Test Client");
        expect(headers["x-bitfab-client-version"]).toBe("1.2.3");
        expect(headers["x-bitfab-client-os"]).toBe(os.platform());
        expect(headers["x-bitfab-client-arch"]).toBe(os.arch());
        expect(headers["x-bitfab-client-node-version"]).toBe(process.version);
        expect(headers["x-bitfab-install-id"]).toBeDefined();
        expect(headers["x-bitfab-client-timezone"]).toBeDefined();
        expect(headers["x-bitfab-client-locale"]).toBeDefined();
    });
    it("does not include transport headers (auth, content-type, accept)", () => {
        const headers = buildBitfabClientHeaders("1.2.3", testPlatform);
        expect(headers.Authorization).toBeUndefined();
        expect(headers["Content-Type"]).toBeUndefined();
        expect(headers.Accept).toBeUndefined();
    });
});
describe("buildBitfabRequestHeaders", () => {
    it("composes Content-Type, Authorization, and identity headers", () => {
        const headers = buildBitfabRequestHeaders("sk-test", "1.2.3", testPlatform);
        expect(headers["Content-Type"]).toBe("application/json");
        expect(headers.Authorization).toBe("Bearer sk-test");
        expect(headers["x-bitfab-client-name"]).toBe("test-cli");
        expect(headers["x-bitfab-client-version"]).toBe("1.2.3");
        expect(headers["x-bitfab-install-id"]).toBeDefined();
    });
    it("does not include Accept (callers add transport-specific headers)", () => {
        const headers = buildBitfabRequestHeaders("sk-test", "1.2.3", testPlatform);
        expect(headers.Accept).toBeUndefined();
    });
});
